" f"Focus on failures, limitations, overlooked alternatives." }, ] # Run all searches in parallel (genuine speedup — not possible single-threaded) async def run_search(perspective: dict) -> dict: response = client.messages.create( model="claude-sonnet-4-20250514", max_tokens=1500, system=f"You are a {perspective['role']}. Be thorough and specific. " f"Cite concrete examples, numbers, and dates.", messages=[{"role": "user", "content": perspective["prompt"]}], ) return { "role": perspective["role"], "findings": response.content[0].text, } results = await asyncio.gather( *[run_search(p) for p in search_perspectives] ) # Synthesis agent — combines perspectives, flags contradictions all_findings = "

